</code></pre> <pre><code>import java.net.URI;
import java.net.http.*;
import java.net.http.HttpRequest.BodyPublishers;

HttpClient client = HttpClient.newHttpClient();

String body = """
    {
      "client_id":     "your-client-id",
      "client_secret": "your-client-secret"
    }
    """;

HttpRequest request = HttpRequest.newBuilder()
    .uri(URI.create("https://api.heydollr.app/v1/jwt/client/obtain/token"))
    .header("Content-Type", "application/json")
    .POST(BodyPublishers.ofString(body))
    .build();

HttpResponse&lt;String&gt; response = client.send(request, HttpResponse.BodyHandlers.ofString());
System.out.println(response.body());
</code></pre> <pre><code>package main

import (
    "bytes"
    "encoding/json"
    "fmt"
    "io"
    "net/http"
)

func main() {
    payload := map[string]string{
        "client_id":     "your-client-id",
        "client_secret": "your-client-secret",
    }
    body, _ := json.Marshal(payload)

    resp, _ := http.Post(
        "https://api.heydollr.app/v1/jwt/client/obtain/token",
        "application/json",
        bytes.NewBuffer(body),
    )
    defer resp.Body.Close()

    var result map[string]interface{}
    data, _ := io.ReadAll(resp.Body)
    json.Unmarshal(data, &amp;result)
    fmt.Println("Token:", result["access_token"])
}
</code></pre>

